tutorialsIndex_pt = {"Básico", "Sistemas Básicos", "Sistemas Avançados", "NPCs", "Moedas", "Doaçăo"}

tutorialsInfo_pt = {
-- Básico --
    {
        {name = "01. Introduçăo", text = "PokeFANS é um servidor com uma base única e sistemas exclusivos.\n\nBuscamos trazer sempre inovaçăo e diversăo para todos nossos jogadores.", img = "imgs/basic/b1"}, 
        {name = "02. Controlar Objetos", text = "Para controlar itens, basta clicar e segurar o botăo esquerdo do mouse pressionado e arrastá-lo para onde quiser.", img = "imgs/basic/b2"}, 
        {name = "03. Interface", text = "Possuimos uma interface única e integrada para os jogadores, nela vocę tem acesso ŕ todos os comandos necessários para sua jogatina.", img = "imgs/basic/b3"}, 
        {name = "04. Order", text = "Com o order, vocę pode controlar seu pokémon em batalha, escolhendo onde seu pokémon deve se posicionar.\n\nVocę pode usar o order clicando no ícone ou com o atalho 'BOTĂO DO MEIO DO MOUSE'.\n\nAlguns pokémons possuem habilidades que necessitam do uso do ORDER para serem ativadas, como Fly, Ride, Rock Smash, Cut, entre outras.\n\nVocę pode conferir mais sobre estas habilidades na aba 'habilidades'.", img = "imgs/basic/b4"},		       
        {name = "05. Pokédex", text = "Com a pokédex, vocę pode checar informaçőes dos pokémons, como status, habilidades, evoluçőes, moveset, etc...\n\nToda vez que vocę descobrir um pokémon novo vocę ganhará experięncia por isso.\n\nVocę pode usar a pokédex clicando no ícone e depois clicando em um pokémon, ou usando o atalho 'CTRL+D' e em seguida clicar em um pokémon.", img = "imgs/basic/b5"}, 
        {name = "06. Mochila", text = "A mochila é onde todos os seus itens, pokémons e espólios ficam armazenados.\n\nPara abrir a mochila, basta clicar no ícone ou usar o atalho 'CTRL+I'.", img = "imgs/basic/b6"},       
		{name = "07. Pesca", text = "Com a vara de pesca vocę pescar pokémons selvagens em qualquer fonte de água, sendo um ótimo método de up.\n\nPara pescar, basta clicar no ícone e depois clicar em um corpo de água, ou utilizar o atalho 'CTRL+Z'.\n\nVocę pode alternar entre suas varas de pesca utilizando o atalho 'CTRL+X', porém, vocę precisa ter liberado as outras varas antes.", img = "imgs/basic/b7"},        
        {name = "08. Evoluçăo", text = "O ícone de evoluçăo permite que vocę evolua seus pokémons, desde que eles evoluam por level ou amor.\n\nPara evoluir um pokémon basta clicar no ícone e depois em seu pokémon que deseja evoluir, ou utilizar o atalho 'CTRL+E'.", img = "imgs/basic/b8"},
        {name = "09. Carteira", text = "A carteira mostra quanto dinheiro vocę tem salvo no banco e quantos tokens seu personagem tem.\n\nVocę pode conferir mais sobre os tokens na aba 'moedas'.", img = "imgs/basic/b9"},
        {name = "10. Caixa de Insígnia", text = "A caixa de insígnia serve para vocę checar quais insígnias seu personagem já conquistou.\n\nCada insígnia aumenta o limite de diferença de level em 5 níveis.\n\nVocę pode conferir mais sobre o sistema de níveis na aba 'sistemas'.", img = "imgs/basic/b10"},
        {name = "11. PokéBAR", text = "A pokébar é uma interface para facilitar sua jogatina, vocę pode escolher rapidamente qual pokémon deseja soltar com apenas um clique. Basta clicar no ícone do pokémon desejado.\n\nVocę pode soltar seus pokémons com os atalhos 'CTRL+F1', 'CTRL+F2', 'CTRL+F3', 'CTRL+F4', 'CTRL+F5' e 'CTRL+F6', sendo a ordem dos ícones.", img = "imgs/basic/b11"},
		{name = "12. MoveBAR", text = "A movebar é uma interface para facilitar sua jogatina, vocę pode escolher rapidamente qual ataque deseja usar com apenas um clique. Basta clicar no ícone do ataque desejado.\n\nVocę pode atacar utilizando as teclas de atalho 'F1', 'F2', 'F3', 'F4', 'F5', 'F6', 'F7', 'F8', 'F9', 'F10', 'F11' e 'F12', sendo a ordem dos ícones.", img = "imgs/basic/b12"},
		{name = "13. Minimapa", text = "O minimapa mostra sua localizaçăo atual.\n\nVocę pode dar zoom-in e zoom-out utilizando a roleta do mouse.", img = "imgs/basic/b13"},  
        {name = "14. Conversando com NPC", text = "Vocę pode iniciar uma conversa com um NPC ao clicar em nele com o botăo esquerdo do mouse.\n\nVocę pode fazer escolhas de diálogo clicando em cima do texto azul, caso o NPC possua escolhas.", img = "imgs/basic/b14"},
    },
-- Sistemas Basicos--
    {
        {name = "01. Autoloot e Loot Comum", text = "O autoloot é ativado automaticamente quando voce cria seu personagem. Todo o loot dropado pelos pokémons selvagens irăo diretamente para seu inventario. Para desativar o autoloot basta digitar !autoloot.\n\nO loot comum é o loot que todo pokémon de certa tipagem dropa, por exemplo, todo pokémon de água sempre vai ter a chance de dropar Water Gem, Water Pendant, etc...\nEsses loots năo aparecem na mensagem de loot, porém, săo pegos no autoloot.", img = "imgs/sistemabasic/sb1"},
        {name = "02. Captura", text = "Para capturar um pokémon, voce deve primeiro derrota-lo em combate.\nApós derrotado, vocę pode jogar uma poké bola nele e tentar a captura.\nPara utilizar uma pokébola basta clicar com o botăo direito nela e depois com o botăo esquerdo no pokémon derrotado.\nSe a pokébola piscar verde no final, vocę capturou.\nSe a pokébola piscar vermelha no final, vocę năo capturou.\n\nEm nosso servidor possuimos diferentes tipos de poké bolas.\nPokeball - Possui 1.0x de captura.\nGreatball - Possui 1.5x de captura.\nUltraball - Possui 2.0x de captura.\nMasterball - Sempre captura o pokémon.\nParkball - Possui 5.0x de captura, só funciona no PokePARK.\nSaffariball - Possui 1.5x de captura, só funciona no Saffari.\nHeavyball - Aumenta a chance de captura de acordo com o peso do pokémon derrotado.\nDuskball - Possui 3.5x de captura, só funciona a noite.\nLoveball - Possui 4.0x de captura, só funciona no mesmo pokémon que vocę está utilizando.\nNetball - Possui 3.5x de captura, só funciona em pokémons inseto e água.\nPremierball - Uma pokebola especial que possui 1.0x de captura, porém adiciona uma aura ao pokémon quando captura.\n\nAs pokébolas normais, como Pokeball, Greatball e Ultraball podem ser compradas no NPC Mark, no trading center.\nAs pokébolas especiais, como Heavyball, Duskball, Loveball, Netball e Premierball podem ser adquiridas com o NPC Token Collector no trading center.\nAs pokébolas Saffari e Parkball săo de uso exclusivo dos locais.\nA pokébola mais forte do jogo, Masterball, deve ser obtida por meio de quests e desafios.", img = "imgs/sistemabasic/sb2"},
        {name = "03. Level e EXP Share.", text = "Em nosso servidor, os pokémons possuem nível e isso influencia diretamente o combate. Seu pokémon precisa de nível para evoluir, usar ataques, etc...\nO pokémon que vocę utilizar para abatar o pokémon selvagem será o que receberá experięncia. Caso vocę esteja com um EXP Share em algum outro pokémon, ele também receberá experięncia, mesmo năo participando do combate.\n\nEXP Share\nO exp share pode ser obtido no NPC Token Collector, no trading center. Para dar o exp share a um pokémon, basta clicar com o botao direito no exp share e o botao esquerdo no pokémon que deseja.", img = "imgs/sistemabasic/sb3"},
        {name = "04. Fly, ride e surf", text = "Se o seu pokémon possuir uma dessas habilidades, vocę poderá utiliza-las para ter uma melhor mobilidade.\n\nCom o Fly, basta utilizar o order em vocę mesmo com o pokémon solto, que ele irá até vocę e iniciará o fly. Utilize PageUp para subir um andar e PageDown para descer um andar. Para sair do fly basta dar order em vocę mesmo novamente.\n\nCom o ride, basta utilizar o order em vocę mesmo para montar e desmontar.\n\nCom o surf, basta andar em um corpo de água com o pokémon solto que vocę começa a surfar.", img = "imgs/sistemabasic/sb4"},
    },		
-- Sistemas Avançados --
    {
        {name = "01. TM System",      text = "O sistema de TM permite que vocę crie o pokémon perfeito pro seu estilo de jogo. Vocę utiliza o item 'clean disk' para ensinar TMs especificos para o seu pokémon. Para abrir a interface de TM basta segurar CTRL e clicar em cima do seu pokémon, em seguida clicar em 'TM System'.\n\nCada TM tem seu próprio custo, cooldown, nível necessário e pokémons que podem aprender, entăo nem todos os pokémons podem aprender todos os TMs.", img = "imgs/sistemasadv/sa1"},
        {name = "02. EV System",     text = "O sistema de EV permite que voce balanceie melhor o seu pokémon, de acordo com sua necessidade. Cada pokémon pode receber até 300 pontos de EV e pode colocar até 150 pontos em cada status.\nO status HP aumenta a vida em 10 para cada ponto gasto, o status ATK aumenta o ataque em 1 para cada ponto gasto e o status DEF aumenta a defesa em 1 para cada ponto gasto. Para receber pontos basta abater os pokémons selvagens que vocę recebe EV Points.\n\nPara abrir a interface de EV basta segurar CTRL e clicar em cima do seu pokémon, em seguida clicar em 'EV System'.", img = "imgs/sistemasadv/sa2"},
        {name = "03. Dungeon System",         text = "Em nosso servidor, possuimos um sistema de Dungeon instanciado, onde vocę pode entrar e desafiar os pokémons lendários.\nPara entrar na dungeon, basta acessar o dispositivo no último andar do centro pokémon.", img = "imgs/sistemasadv/sa3"},
        {name = "04. Tera System", 			text = "Pokémon Tera, Pokémon Terastal ou Tera System, é quando um pokémon selvagem spawna com uma tipagem TERA. Pokémons com a tipagem TERA ignoram a tipagem natural do pokémon e possuem apenas a tipagem TERA.\nUm pokémon TERA de Fogo, aplicará dano e receberá dano como se fosse do tipo Fogo originalmente. Adicionalmente, caso o pokémon utilize um ataque da mesma tipagem que seu TERA, ele causará STAB equivalente a 2.0x, enquanto um pokémon sem TERA causará 2.0x.\n\nPokémons TERA spawnam naturalmente pelo mundo e possuem uma aura única dada ŕ eles, o que os diferencia totalmente dos outros pokémons comuns. Pokémons teras săo extremamente raros e valiosos.", img = "imgs/sistemasadv/sa4"},
        {name = "05. Smeargle System",         text = "O Smeargle é um pokémon único comparado ŕ todos os outros. Smeargle pode aprender ataques de outros pokémons, utilizando o seu ataque 'Sketch', cada smeargle possui 8 sketches que podem copiar 8 ataques diferentes.\n\nPara copiar um ataque de um pokémon, use o order no smeargle, para desbloquear ele. Depois, de target no pokemon que queira copiar e use o ataque da mesma numeraçăo do ataque que voce quer copiar.\n\nExemplo: Se eu desejo copiar o ataque M4 de um pokémon, devo usar o Sketch 4.", img = "imgs/sistemasadv/sa5"},
        {name = "06. Ditto System",      text = "Ditto é outro pokémon único, ele consegue copiar qualquer pokémon, desde que năo seja lendário. Ditto copia os status, aparęncia e ataques do pokémon, sendo um ótimo coringa no time. Capturar um Ditto năo é uma tarefa muito fácil, ele se esconde pelo mundo se disfarçando de outros pokémons, entăo vocę só vai saber que é um ditto quando derrotar o pokémon e uma gosma rosa aparecer no chăo!\n\nPara copiar um pokémon com seu ditto, basta utilizar Order no pokémon que deseja copiar e para voltar ao normal, basta usar order no ditto.", img = "imgs/sistemasadv/sa6"},
        {name = "07. Computer System",         text = "Se voce adquirir um computador pessoal com o NPC Token Collector no trading center, vocę pode fazer uma variedade de coisas no seu computador (dentro de casa).\nPoké Food - Delivery de comida pra vocę, as melhores comidas do mercado na palma da sua măo.\nRemove Held - Permite que vocę remova um held do seu pokémon, muito útil se vocę farma itens com 'Pickup' e 'PayDay'.\nRemove Exp Share - Permite remover o expshare de algum pokémon.\nRotom - Permite mudar a forma do Rotom.\nDeoxys - Permite mudar a forma do Deoxys.", img = "imgs/sistemasadv/sa7"},
        {name = "08. Held System",         text = "Helds aumentam status específicos ou causam bonus em alguns efeitos. Helds podem ser adquiridos com o NPC Token Collector no trading center.\nOs helds possuem dois tiers, sendo um para pokémons de nível 50- e outro para pokémons de nível 50+.\n\nHeld Attack - aumenta o ataque do pokémon.\nHeld Defense - aumenta a defesa do pokémon.\nHeld Experience - aumenta a experiencia que o pokemon recebe.\nHeld Burn - aumenta o dano do status burn causado pelo pokémon.\nHeld Poison - aumenta o dano do status poison causado pelo pokémon.\nHeld Vitality - aumenta a vida do pokémon.\nHeld Wing - aumenta a velocidade de voo do pokémon.\nHeld Cure - chance de curar condiçőes do pokémon a cada segundo.", img = "imgs/sistemasadv/sa8"},
        {name = "09. Reborn System",        text = "O sistema de Reborn, serve para vocę voltar ao nível um e poder refazer algumas quests. Algumas dungeons e sistemas tem um requisito mínimo de reborns necessários.\nPara rebornar basta atingir o nível 1000 e digitar /reborn .\nO limite máximo de reborns é 10.", img = "imgs/sistemasadv/sa9"},
        {name = "10. PokePARK",text = "PokePARK é um evento global que acontece toda terça, quinta, sábado e domingo, as 11:00, 16:00 e 21:00.\nPara acessar o PokePARK voce deve ter um PokePARK ticket, que pode ser obtido no shop do jogo, por quests ou trade.\n\nAo entrar no PokePARK, voce receberá 50 parkballs, săo pokébolas com o multiplicador de cacch altíssimos, tornando o catch muito fácil. Porém, para ao capturar um pokémon no poképark, vocę năo fica com ele, e sim, ganha pontos.\nEsses pontos podem ser utilizados para comprar os pokémons do PokePARK, caso voce os tenha capturado.\nA entrada do PokePARK fica ŕ esquerda do centro pokémon de Port Harbor, utilize !teleport port harbor com algum pokémon com teleport para ir até lá.", img = "imgs/sistemasadv/sa10"},
        {name = "11. Saffari Zone",              text = "A Saffari Zone é uma área artificial com diversos pastos com vários pokémons. Quando vocę entra em um pasto, ninguém mais pode entrar até vocę sair. O saffari tem uma variedade muito grande de pastos e pokémons pokémons exclusivos. Para entrar no Saffari, basta ir a port harbor com o teleport (!teleport port harbor) e ir a direita do centro pokémon. Para entrar vocę precisará de 100 tokens.", img = "imgs/sistemasadv/sa11"},
        {name = "12. Food System",            text = "As comidas no jogo servem como as potions para pokémons, porém para jogadores. Ao consumir uma comida, vocę ira regenerar vida a cada segundo, de acordo com a comida utilizada.\n\nDiversos NPCs vendem comida pelo mundo, e caso vocę possua um computador, pode optar por comprar pelo Poké Food.", img = "imgs/sistemasadv/sa12"},
        {name = "13. Mega System",             text = "Alguns pokémons possuem sua Mega Evoluçăo e podem spawnar evoluidos pelo mapa. Derrotar um desses pokémons te garante a chance de dropar uma mega stone daquele pokémon. Ao utilizar a mega stone em um pokémon seu, ele se tornará mega também, ficando ainda mais forte.", img = "imgs/sistemasadv/sa13"},
        {name = "14. Quest Log",         text = "Quest Log é uma ferramenta de fácil acesso que facilita a vida do jogador. Seu intuito é mostrar as quests disponíveis para o seu nível, sempre atualizando conforme voce upa.\nO Quest log também, mostra as quests que vocę já finalizou, pra poder lembrar quais foram feitas ou năo.\n\nPara acessar o quest log basta clicar no ícone no canto superior direito.", img = "imgs/sistemasadv/sa14"},
		{name = "15. Random Encounter",         text = "Random Encounter permite que vocę encontre pokémons lendários raramente quando derrota pokémons.\nCaso derrote pokémons de Johto, vocę tem a chance de encontrar um dos căes lendários.\nCaso derrote pokémons de Hoenn, vocę tem a chance de encontrar Latios ou Latias.\nCaso derrote pokémons de sinnoh, vocę tem chance de encontrar Cresselia, caso tenha feito a quest de liberaçăo.", img = "imgs/sistemasadv/sa15"},
	},	

-- NPCs --
	{
        {name = "01. Nurse",      text = "Presente em todos os centros pokémons, cura seus pokémons.", img = "imgs/npc/n1"},
		{name = "02. Job Manager",      text = "Presente no segundo andar do centro pokémon de saffron, possibilita o jogador aderir uma profissăo.", img = "imgs/npc/n2"},
		{name = "03. Eva",      text = "Presente no segundo andar do centro pokémon de saffron, responsável pelo sistema de banco.", img = "imgs/npc/n3"},
		{name = "04. Mark",      text = "Presente no trading center, vende itens essenciais para a jornada de um treinador e compra itens dropados dos pokémons.", img = "imgs/npc/n4"},
		{name = "05. Pokémon Collector",      text = "Presente no trading center, compra pokémons dos jogadores.", img = "imgs/npc/n5"},
		{name = "06. Henry",      text = "Presente no trading center, compra e vende pedras evolutivas.", img = "imgs/npc/n6"},
		{name = "07. Token Collector",      text = "Presente no trading center, troca itens por tokens dos jogadores.", img = "imgs/npc/n7"},
		{name = "08. Architect",      text = "Presente no trading center, vende de decoraçăo para casas.", img = "imgs/npc/n8"},
		{name = "09. NPC Trade",      text = "Espalhados pelo mundo inteiro, estes NPCs irăo lhe pedir algo e em troca lhe darăo algum pręmio.", img = "imgs/npc/n9"},
		{name = "10. NPC Duel",      text = "Espalhados pelo mundo inteiro, estes NPCs irăo duelar com vocę e caso vocę vença, irá receber um pręmio.", img = "imgs/npc/n10"},
		{name = "11. Mega Collector",      text = "Presente no trading center, compra mega stones por pack de pé (moeda de doaçăo).", img = "imgs/npc/n11"},
		
