-- Moedas --       
	{
        {name = "01. Gold Coin",      text = "A moeda principal do jogo, possuindo 4 variaçőes.\n\nGold Coin: Cada gold coin equivale ŕ 1 gold coin.\nPlatinum Coin: Cada platinum coin equivale a 100 gold coins.\nCrystal Coin: Cada crystal coin equivale a 100 platinum coins, que equivale a 10.000 gold coins.\nQuartz Coin: Cada quartz coin equivale a 100 crystal coin, que equivale a 1.000.000 gold coins.", img = "imgs/base"},
		{name = "02. Token",      text = "O token é uma moeda secundária do jogo, que vocę recebe ao completar quests, tasks, trials e bosses.\nVocę pode trocar os tokens no NPC Token Collector, no TC.", img = "imgs/base"},
		{name = "03. Park Points",      text = "Moeda utilizada para comprar pokémons e itens do PokePARK. Adquirida ao completar o evento PokePARK.", img = "imgs/base"},
		{name = "04. Pack de Pé",      text = "Pack de Pé ou PP é a moeda de doaçăo do servidor, para cada 1 real doado vocę recebe 1 pack de pé.\nVocę pode utilizar os packs de pé para comprar itens em nosso shop.", img = "imgs/base"},
 	},	 
	
-- Doaçăo --       
	{
        {name = "01. Introduçăo ŕ doaçăo",      text = "O servidor é um fă-game, logo, năo temos intençőes lucrativas. Todas as doaçőes feitas săo para ajudar a manter o servidor online.\nCaso vocę decida doar, será muito apreciado, porém, lembre-se, doe somente se vocę gostar do jogo e se tiver condiçőes de fazer isso!", img = "imgs/base"},
		{name = "02. Instruçőes para doar",      text = "Para doar vocę deve enviar um pix para: \nowatari.zayon@gmail.com\nApós isso, encaminhe um print ou informe ao ADM no discord/ingame para que ele cheque a doaçăo.\nAssim que a doaçăo for constatada, será entregue ao seu depot os packs de pé.", img = "imgs/base"},
 	},	 
}